import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider } from '@mui/material';
import { PieChart, ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface EmissionCategory {
  category: string;
  emissions: number;
}

interface CarbonFootprintData {
  dailyEmissions: {
    total: number;
    unit: string;
  };
  categoryBreakdown: EmissionCategory[];
  monthlyTrend: number[];
}

export default function Widget() {
  const data = response.data as CarbonFootprintData;
  const meta = response.meta;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#2C2C2C', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Daily Carbon Emissions
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: meta.primaryColor }}>
              {data.dailyEmissions.total} {data.dailyEmissions.unit}
            </Typography>
          </Box>

          <Divider sx={{ borderColor: '#444' }} />

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Emissions by Category
            </Typography>
            <PieChart
              height={120}
              series={[
                {
                  data: data.categoryBreakdown.map((item) => ({
                    value: item.emissions,
                    label: item.category,
                  })),
                  color: [meta.primaryColor, meta.accentColor, '#FFC107', '#3F51B5'],
                },
              ]}
              sx={{
                '& .MuiPieElement-root': {
                  stroke: '#2C2C2C',
                  strokeWidth: 1,
                },
              }}
            />
          </Box>

          <Divider sx={{ borderColor: '#444' }} />

          <Box sx={{ width: '100%', height: 140 }}>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Monthly Emissions Trend
            </Typography>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: data.monthlyTrend,
                  color: meta.primaryColor,
                  curve: 'linear',
                  showMark: false,
                },
              ]}
              xAxis={[
                {
                  data: data.monthlyTrend.map((_, index) => index + 1),
                  id: 'months',
                },
              ]}
              yAxis={[{ id: 'emissions' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="months"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="emissions"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
